	actionEvent, err := cc.ReadEvent(ctx, instanceID, "StartEvent_1")
	if err != nil {
		return err
	}

	if actionEvent.EventState != ENABLED {
		errorMessage := fmt.Sprintf("Event state %s is not allowed", actionEvent.EventID)
		fmt.Println(errorMessage)
		return fmt.Errorf(errorMessage)
	}

	cc.ChangeEventState(ctx, instance, "StartEvent_1", COMPLETED)
	stub.SetEvent("StartEvent_1", []byte("Contract has been started successfully"))
	cc.SetInstance(ctx, instance)
